# Data representing Argentina's Olympic achievements
olympic_achievements = {
    '2016': {'medal': 'gold', 'result': 'defeated Belgium 4-2'},
    '2020': {'medal': 'silver', 'result': 'lost to Belgium in final'}
}

# Function to check if Argentina won gold in Olympics
def check_gold_medal(achievements):
    for year, achievement in achievements.items():
        if achievement['medal'] == 'gold':
            return True
    return False

# Check Argentina's gold medal status
argentina_has_gold = check_gold_medal(olympic_achievements)
print(f"Argentina has won Olympic gold: {argentina_has_gold}")

This code checks if Argentina has won a gold medal in the Olympics based on the provided data.
